examples.code:
// State: Created
STATE OrderCreated
 EVENT: confirm() -> TRANSITION to OrderConfirmed
 EVENT: cancel() -> TRANSITION to OrderCancelled

// State: Confirmed
STATE OrderConfirmed
 EVENT: process() -> TRANSITION to OrderProcessed
 EVENT: cancel() -> TRANSITION to OrderCancelled

// State: Processed
STATE OrderProcessed
 EVENT: ship() -> TRANSITION to OrderShipped

// State: Shipped
STATE OrderShipped
 EVENT: deliver() -> TRANSITION to OrderDelivered

// State: Cancelled (Final State)
STATE OrderCancelled

// State: Delivered (Final State)
STATE OrderDelivered
